    policy = load_policy(MANIFEST_PATH)
    for target in policy.targets:
        if target.name.startswith("ios-"):
            assert target.build_only, f"{target.name} should be build-only"
            assert not target.capabilities, f"{target.name} should have no capabilities"


def test_macos_arm64_egl_is_smoke_build() -> None:
    policy = load_policy(MANIFEST_PATH)
    target = next(t for t in policy.targets if t.name == "macos-arm64-egl")
